fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let n = nums.len();
    let k_usize = k as usize;

    // Helper function to check if an index i is a peak in the current configuration
    let is_peak = |i: usize, current_nums: &[i64]| -> bool {
        let prev = current_nums[(i + n - 1) % n];
        let next = current_nums[(i + 1) % n];
        current_nums[i] > prev && current_nums[i] > next
    };

    // Check initial peaks
    let mut initial_peaks = 0;
    for i in 0..n {
        if is_peak(i, &nums) {
            initial_peaks += 1;
        }
    }

    if initial_peaks >= k_usize {
        return 0;
    }

    // Greedy simulation approach
    let mut current_nums = nums;
    let mut current_cost: i64 = 0;
    let mut achieved_peaks = initial_peaks;

    // Maximum possible peaks is floor(n/2)
    if k_usize > n / 2 {
        return -1;
    }

    loop {
        if achieved_peaks >= k_usize {
            return current_cost;
        }

        let mut best_cost_increase = i64::MAX;
        let mut best_index = None;
        let mut improvement_found = false;

        // Find the single cheapest operation that creates a new peak
        for i in 0..n {
            if is_peak(i, &current_nums) {
                continue;
            }

            let prev = current_nums[(i + n - 1) % n];
            let next = current_nums[(i + 1) % n];
            let required_value = std::cmp::max(prev, next) + 1;

            let cost = std::cmp::max(0, required_value - current_nums[i]);

            if cost < best_cost_increase {
                best_cost_increase = cost;
                best_index = Some(i);
                improvement_found = true;
            }
        }

        if !improvement_found {
            // Cannot create any more peaks
            return -1;
        }

        // Apply the cheapest improvement found
        let i_star = best_index.unwrap();
        let prev = current_nums[(i_star + n - 1) % n];
        let next = current_nums[(i_star + 1) % n];
        let required_value = std::cmp::max(prev, next) + 1;

        // The cost is the difference between the new value and the old value
        let cost_to_apply = required_value - current_nums[i_star];

        current_cost += cost_to_apply;
        current_nums[i_star] = required_value;

        // Recalculate peaks (necessary because increasing i_star might affect its neighbors' peak status)
        let mut new_peaks = 0;
        for i in 0..n {
            if is_peak(i, &current_nums) {
                new_peaks += 1;
            }
        }
        achieved_peaks = new_peaks;
    }
}
